import React, { useState } from 'react';
import citiesData from '../data/cities.json';

export default function AdminDashboard(){
  const [cities, setCities] = useState(citiesData);
  const [editing, setEditing] = useState(null);
  const [message, setMessage] = useState('');

  function startEdit(id){
    const c = cities.find(x => x.id === id);
    setEditing({...c});
  }

  function save(){
    // Persist change to backend
    fetch(`/api/cities/${editing.id}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editing)
    }).then(async res => {
      if(!res.ok) throw new Error('Save failed');
      const updated = await res.json();
      setCities(prev => prev.map(p => p.id === updated.id ? updated : p));
      setEditing(null);
      setMessage('Saved to server.');
      setTimeout(()=>setMessage(''), 4000);
    }).catch(err => {
      console.error(err);
      setMessage('Error saving. Is the backend running?');
      setTimeout(()=>setMessage(''), 4000);
    });
  }

  return (
    <div>
      <div className="card">
        <h3>Admin Dashboard</h3>
        <div className="small">Manage city information and services (mock UI)</div>
      </div>
      <div className="grid">
        <div>
          <div className="card">
            <h4>Cities</h4>
            {cities.map(c => (
              <div key={c.id} className="list-item" style={{display:'flex', justifyContent:'space-between', alignItems:'center'}}>
                <div>
                  <strong>{c.name}</strong>
                  <div className="small">Population: {c.population.toLocaleString()}</div>
                </div>
                <div>
                  <button className="button" onClick={()=>startEdit(c.id)}>Edit</button>
                </div>
              </div>
            ))}
          </div>
        </div>
        <aside>
          <div className="card">
            {editing ? (
              <div>
                <h4>Edit {editing.name}</h4>
                <label className="small">Population</label>
                <input className="input" value={editing.population} onChange={e=>setEditing({...editing, population: Number(e.target.value)})} />
                <div style={{marginTop:8}}>
                  <button className="button" onClick={save}>Save</button>
                  <button style={{marginLeft:8}} onClick={()=>setEditing(null)}>Cancel</button>
                </div>
              </div>
            ) : (
              <div className="small">Select a city to edit its basic info</div>
            )}
            {message && <div style={{marginTop:8}} className="small">{message}</div>}
          </div>
        </aside>
      </div>
    </div>
  );
}
